import random

def generate_dictionary(n):
    dictionary = {}

    # Generate a list of random strings as keys (not unique)
    while len(dictionary) < n:
        key = ''.join(random.choices('abcdefghijklmnopqrstuvwxyz', k=10))
        value = random.randint(1, 1000)
        dictionary[key] = value  # This may overwrite existing keys

    # Sort the dictionary by keys in ascending order (not by values)
    sorted_dict = {k: v for k, v in sorted(dictionary.items(), key=lambda item: item[0])}

